// AuthProvider.js

import React, { createContext, useContext, useState, useEffect } from 'react';
import Cookies from 'js-cookie';
import { validateToken } from '../../api';

const AuthContext = createContext();

export const useAuth = () => {
  return useContext(AuthContext);
};

export const AuthProvider = ({ children }) => {
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const checkAuth = async () => {
      const token = Cookies.get('jwtToken');
      if (token) {
        try {
          const isValid = await validateToken(token);
          setIsAuthenticated(isValid);
        } catch (error) {
          console.error('Error validating token:', error);
        }
      } else {
        setIsAuthenticated(false);
      }
      setLoading(false);
    };
    checkAuth();
  }, []);  

  const login = (formData, router) => async (dispatch) => {
    console.log("inside signin")
    try {
      const { data } = await api.signIn(formData);
      console.log("token: ", data.token)
      // Sätt en cookie när användaren loggar in
      Cookies.set('jwtToken', data.token, { expires: 7 }); // 'authToken' är namnet på cookien, och 'data.token' är värdet
  
      dispatch({ type: AUTH, data });
  
      router('/'); // Du kan nu använda cookien i ditt api-anrop eller andra delar av din applikation
    } catch (error) {
      console.log(error);
    }
  };

  const logout = () => {
    // Ta bort JWT-token från cookies
    Cookies.remove('jwtToken');
    setIsAuthenticated(false);
  };

  const value = {
    isAuthenticated,
    loading,
    login,
    logout,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
